// Build streetwear digest (text + HTML)
const items = $input.all();
const seen = new Set();
const out = [];
// Streetwear keywords (brands, drops)
const kw = [
  /streetwear/i, /sneaker/i, /sneakers/i, /air\s*jordan/i, /jordan\s*\d+/i, /nike/i, /adidas/i, /new\s*balance/i,
  /supreme/i, /palace/i, /kith/i, /bape|a\s*bathing\s*ape/i, /stussy|stüssy/i, /wtaps/i, /cdg|comme\s*des\s*garçons/i,
  /capsule/i, /lookbook/i, /collection/i, /collab|collaboration/i, /drop/i, /release/i, /raf\s*simons/i, /yeezy/i
];
function isRelevant(title, desc){ const t=`${title||''} ${desc||''}`; return kw.some(re=>re.test(t)); }
for (const it of items){
  const j = it.json||{};
  const title = j.title || '';
  const link = (typeof j.link==='string'? j.link : (j.link?.url || ''));
  const desc = j.description || j.summary || '';
  const dateStr = j.pubDate || j.isoDate || j.published || j.date || '';
  let pub = new Date(dateStr); if (isNaN(pub)) pub = new Date();
  if (!link) continue;
  if (!isRelevant(title, desc)) continue;
  const key = link.split('?')[0]; if (seen.has(key)) continue; seen.add(key);
  let host=''; try { host = new URL(link).hostname.replace(/^www\./,''); } catch(e) {}
  out.push({ title, link, host, pub });
}
// sort & limit
out.sort((a,b)=>b.pub - a.pub);
const selected = out.slice(0, 25);
// build
const now = new Date();
const y = now.getFullYear(); const m = String(now.getMonth()+1).padStart(2,'0'); const d = String(now.getDate()).padStart(2,'0');
const subject = `MOD 1 // Streetwear Daily — ${y}-${m}-${d}`;
let text = 'Streetwear Daily — latest drops & headlines (24h)\n\n';
let html = '<h2 style="margin:0 0 12px;">Streetwear Daily — latest drops & headlines (24h)</h2><ul style="padding-left:16px;">';
for (const a of selected){ const dt = a.pub.toISOString().slice(0,10); text += `• ${a.title} — ${a.host} (${dt})\n  ${a.link}\n`; html += `<li style="margin-bottom:8px;"><a href="${a.link}" style="color:#00F0FF;text-decoration:none;">${a.title}</a> <span style="color:#777;">— ${a.host} (${dt})</span></li>`; }
if (selected.length===0){ text += '(No qualifying streetwear items in last 24h)\n'; html += '<li>(No qualifying streetwear items in last 24h)</li>'; }
text += '\nWear the Prototype.'; html += '</ul><p>Wear the Prototype.</p>';
return [{ json: { subject, text, html } }];
